const feeds = [
  { name: 'TechCrunch', url: 'https://techcrunch.com/feed/' },
  { name: 'The Verge', url: 'https://www.theverge.com/rss/index.xml' },
  { name: 'Ars Technica', url: 'https://feeds.arstechnica.com/arstechnica/index' },
  { name: 'MIT Tech Review', url: 'https://www.technologyreview.com/feed/' },
  { name: 'BBC Africa', url: 'https://feeds.bbci.co.uk/news/world/africa/rss.xml' },
  { name: 'Quanta Magazine', url: 'https://api.quantamagazine.org/feed/' },
  { name: 'Aeon', url: 'https://aeon.co/feed.rss' },
  { name: 'AllAfrica', url: 'https://allafrica.com/tools/headlines/rdf/latest/headlines.rdf' }
];
return feeds.map(feed => ({ json: feed }));

const items = [];
for (const item of $input.all()) {
  const body = item.json.data || item.json.body || '';
  const sourceUrl = item.json.url || '';
  let source = 'Unknown';
  if (sourceUrl.includes('techcrunch')) source = 'TechCrunch';
  else if (sourceUrl.includes('theverge')) source = 'The Verge';
  else if (sourceUrl.includes('arstechnica')) source = 'Ars Technica';
  else if (sourceUrl.includes('technologyreview')) source = 'MIT Tech Review';
  else if (sourceUrl.includes('bbc')) source = 'BBC Africa';
  else if (sourceUrl.includes('quantamagazine')) source = 'Quanta Magazine';
  else if (sourceUrl.includes('aeon')) source = 'Aeon';
  else if (sourceUrl.includes('allafrica')) source = 'AllAfrica';
  const itemMatches = body.toString().match(/<item[^>]*>([\s\S]*?)<\/item>/gi) || [];
  const entryMatches = body.toString().match(/<entry[^>]*>([\s\S]*?)<\/entry>/gi) || [];
  const allMatches = [...itemMatches, ...entryMatches].slice(0, 5);
  for (const block of allMatches) {
    const title = (block.match(/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
    const link = (block.match(/<link[^>]*href=["']([^"']+)["']/) || block.match(/<link>([\s\S]*?)<\/link>/) || [])[1] || '';
    const pubDate = (block.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || block.match(/<published>([\s\S]*?)<\/published>/) || [])[1] || '';
    const description = (block.match(/<description>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/) || block.match(/<summary[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/summary>/) || [])[1] || '';
    const cleanDesc = description.replace(/<[^>]+>/g, '').replace(/&[a-z]+;/gi, ' ').trim().slice(0, 300);
    if (title && link) {
      items.push({ json: { title: title.trim(), link: link.trim(), pubDate: pubDate.trim(), description: cleanDesc, source } });
    }
  }
}
return items;

const relevantKeywords = [
  // Tech & AI
  'ai', 'artificial intelligence', 'machine learning', 'data', 'algorithm', 'model', 'openai', 'google', 'microsoft', 'apple', 'meta', 'startup', 'funding', 'silicon valley', 'cloud', 'cybersecurity', 'robotics', 'quantum',
  // Africa
  'africa', 'african', 'kenya', 'nigeria', 'ghana', 'ethiopia', 'rwanda', 'nairobi', 'lagos', 'cairo', 'continent',
  // Science & Philosophy
  'science', 'research', 'study', 'discovery', 'universe', 'consciousness', 'philosophy', 'psychology', 'evolution', 'climate', 'space', 'physics', 'biology',
  // Data & Economics
  'economy', 'gdp', 'inflation', 'market', 'investment', 'billion', 'million', 'growth', 'jobs'
];
const now = Date.now();
const filtered = [];
for (const item of $input.all()) {
  const { title, description, pubDate } = item.json;
  const text = (title + ' ' + description).toLowerCase();
  const isRelevant = relevantKeywords.some(kw => text.includes(kw));
  if (!isRelevant) continue;
  if (pubDate) {
    const articleTime = new Date(pubDate).getTime();
    if (!isNaN(articleTime) && (now - articleTime) > 24 * 60 * 60 * 1000) continue;
  }
  filtered.push(item);
}
return filtered.length > 0 ? filtered : [];

const workflowStaticData = $getWorkflowStaticData('global');
if (!workflowStaticData.processedLinks) workflowStaticData.processedLinks = [];
if (workflowStaticData.processedLinks.length > 500) {
  workflowStaticData.processedLinks = workflowStaticData.processedLinks.slice(-500);
}
const newItems = [];
for (const item of $input.all()) {
  const link = item.json.link;
  if (!workflowStaticData.processedLinks.includes(link)) {
    workflowStaticData.processedLinks.push(link);
    newItems.push(item);
  }
}
return newItems.length > 0 ? newItems : [];

const results = [];
for (const item of $input.all()) {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.deepseek.com/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer YOUR_DEEPSEEK_API_KEY'
    },
    body: {
      model: 'deepseek-chat',
      max_tokens: 500,
      temperature: 0.9,
      messages: [
        {
          role: 'system',
          content: `You are the voice behind @MKimathi_ on X. You are a data professional based in Nairobi with deep interests in tech, AI, African history, philosophy, and science. Your tweets are sharp, curious, and data-driven. You read widely and have strong opinions. You mix intellectual depth with wit.\n\nRules:\n- NEVER include URLs or hashtags\n- Under 280 characters per tweet\n- Write like a real person, not a press release\n- Vary the style: sometimes a sharp stat, sometimes a hot take, sometimes a thought-provoking question\n\nGenerate exactly 3 tweet options:\n1. DATA/FACT — lead with a striking number or fact\n2. HOT TAKE — strong opinion or contrarian angle\n3. THOUGHT — a curious observation or question that makes people think\n\nFormat exactly:\n1. DATA/FACT\n[tweet]\n\n2. HOT TAKE\n[tweet]\n\n3. THOUGHT\n[tweet]`
        },
        {
          role: 'user',
          content: 'Source: ' + item.json.source + ' | Headline: ' + item.json.title + ' | Summary: ' + item.json.description
        }
      ]
    },
    json: true
  });
  const content = response.choices?.[0]?.message?.content || '';
  results.push({ json: { message: { content }, title: item.json.title, source: item.json.source } });
}
return results;

const allDrafts = $input.all();
if (allDrafts.length === 0) return [];
let htmlBody = `<div style="font-family: Arial, sans-serif; max-width: 650px; margin: 0 auto;">
  <h2 style="color: #1a1a2e; border-bottom: 2px solid #16213e; padding-bottom: 8px;">✍️ @MKimathi_ Tweet Drafts — ${new Date().toLocaleString('en-KE', { timeZone: 'Africa/Nairobi' })} EAT</h2>
  <p style="color: #666; font-size: 13px;">${allDrafts.length} new stor${allDrafts.length === 1 ? 'y' : 'ies'} found. Pick your favorites and post manually.</p>`;
for (let i = 0; i < allDrafts.length; i++) {
  const content = allDrafts[i].json.message?.content || '';
  const source = allDrafts[i].json.source || '';
  const title = allDrafts[i].json.title || '';
  htmlBody += `<div style="background: #f9f9f9; border-left: 4px solid #16213e; padding: 16px; margin: 20px 0; border-radius: 4px;">
    <p style="font-size: 11px; color: #999; margin: 0 0 8px 0;">SOURCE: ${source} — ${title}</p>
    ${content.replace(/\n/g, '<br>')}
  </div>`;
}
htmlBody += `<p style="color: #999; font-size: 12px; margin-top: 30px;">Powered by MKimathi Draft Pipeline · n8n</p></div>`;
return [{ json: { htmlBody, count: allDrafts.length } }];
